query:
-- Buscar ID da categoria "Geral"
SELECT id, name FROM categories WHERE name LIKE '%Geral%' OR name LIKE '%geral%';

-- Buscar ID da categoria "Cursos Técnicos"
SELECT id, name FROM categories WHERE name LIKE '%Técnico%' OR name LIKE '%técnico%';

-- Buscar cursos na categoria "Geral"
SELECT c.id, c.title, c.categoryId, cat.name as categoryName 
FROM courses c 
LEFT JOIN categories cat ON c.categoryId = cat.id 
WHERE cat.name LIKE '%Geral%' OR cat.name LIKE '%geral%';

